<script setup lang="ts">
import{ref,onMounted}from'vue';import{onLoad}from'@dcloudio/uni-app';import PageHeader from'../../components/PageHeader.vue';import ServiceIcon from'../../components/ServiceIcon.vue';import{registrationApi,type Department,type Schedule}from'../../api/registration';import{currentPatient}from'../../stores/session'
const step=ref(1),loading=ref(false),selected=ref<Department|null>(null),departments=ref<Department[]>([]),schedules=ref<Schedule[]>([]),selectedDate=ref(0)
const dateOptions=Array.from({length:3},(_,i)=>{const d=new Date();d.setDate(d.getDate()+i);return{label:i===0?'今天':i===1?'明天':`${d.getMonth()+1}/${d.getDate()}`,value:`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`}})
async function loadDepartments(){loading.value=true;try{departments.value=await registrationApi.departments()}finally{loading.value=false}}
async function loadSchedules(){if(!selected.value)return;loading.value=true;try{schedules.value=await registrationApi.schedules(selected.value.id,dateOptions[selectedDate.value].value)}finally{loading.value=false}}
async function choose(item:Department){selected.value=item;step.value=2;await loadSchedules()}
async function changeDate(index:number){selectedDate.value=index;await loadSchedules()}
async function submit(item:Schedule){const patient=currentPatient.value;if(!patient||!selected.value){uni.showToast({title:'未获取到患者信息',icon:'none'});return}const confirmed=await new Promise<boolean>(resolve=>uni.showModal({title:'确认挂号',content:`${patient.realName} · ${selected.value?.name} · ${item.physicianName||'医生'} · ${dateOptions[selectedDate.value].value} ${item.timeSlotName||item.timeSlot||''}`,success:r=>resolve(r.confirm),fail:()=>resolve(false)}));if(!confirmed)return;const result=await registrationApi.create({patientId:patient.patientId,patientName:patient.realName,departmentId:selected.value.id,physicianId:item.physicianId,physicianName:item.physicianName,schedulingId:item.id,visitDate:dateOptions[selectedDate.value].value,visitTime:item.timeSlotName||item.timeSlot,registLevelId:item.registLevelId,registerType:1,operatorName:'患者自助'});uni.showModal({title:'挂号成功',content:String(result.paymentMessage||'请前往“我的就诊”查看挂号记录'),showCancel:false,success:()=>uni.reLaunch({url:'/pages/visits/index'})})}
onLoad(options=>{loadDepartments().then(()=>{const id=Number(options?.departmentId);const name=decodeURIComponent(String(options?.department||''));const matched=departments.value.find(item=>item.id===id)||departments.value.find(item=>item.name===name);if(matched)choose(matched)})});onMounted(()=>{})
</script>
<template><view class="page-shell"><PageHeader title="预约挂号" subtitle="选择科室与就诊时间"/><view class="steps"><view :class="{active:step>=1}"><text>1</text><text>选择科室</text></view><view class="line"/><view :class="{active:step>=2}"><text>2</text><text>选择号源</text></view></view><view v-if="step===1" class="section card"><view class="section-head"><text class="section-title">选择就诊科室</text><text class="section-more">{{loading?'加载中':`共 ${departments.length} 个`}}</text></view><view v-if="departments.length" class="departments"><view v-for="(item,index) in departments" :key="item.id" @tap="choose(item)"><view class="dept-icon-platform"><ServiceIcon type="staff" :tone="['blue','green','orange','purple'][index%4]"/></view><view><text>{{item.name}}</text><text>{{item.description||item.type||'门诊科室'}}</text></view><text>›</text></view></view><view v-else-if="!loading" class="empty">暂无可挂号科室</view></view><template v-else><view class="selected card"><ServiceIcon type="staff" tone="blue"/><view><text>当前科室</text><text>{{selected?.name}}</text></view><text @tap="step=1">重新选择</text></view><scroll-view class="date-scroll" scroll-x><view v-for="(item,index) in dateOptions" :key="item.value" :class="{active:selectedDate===index}" @tap="changeDate(index)">{{item.label}} {{item.value.slice(5)}}</view></scroll-view><view class="section card"><view class="section-head"><text class="section-title">可预约号源</text><text class="section-more">{{loading?'加载中':`剩余 ${schedules.length} 个`}}</text></view><view v-for="item in schedules" :key="item.id" class="doctor"><view class="avatar">{{(item.physicianName||'医').slice(0,1)}}</view><view><text class="doctor-name">{{item.physicianName||'门诊医生'}} {{item.physicianTitle||''}}</text><text>{{item.registLevelName||'普通门诊'}} · {{item.timeSlotName||item.timeSlot}}</text><text class="quota">剩余 {{item.availableQuota??0}} 个号源</text></view><view><text class="price">¥{{Number(item.price||0).toFixed(2)}}</text><button size="mini" @tap="submit(item)">预约</button></view></view><view v-if="!loading&&!schedules.length" class="empty">当日暂无可用号源，请选择其他日期</view></view></template></view></template>
<style scoped lang="scss">.steps{display:flex;align-items:center;justify-content:center;margin:15rpx 30rpx 28rpx}.steps>view:not(.line){display:flex;flex-direction:column;align-items:center;gap:8rpx;color:#9aa4b5;font-size:20rpx}.steps>view>text:first-child{width:45rpx;height:45rpx;border-radius:50%;display:flex;align-items:center;justify-content:center;background:#dce4ef}.steps .active{color:#2878ff!important}.steps .active>text:first-child{background:#2878ff;color:#fff}.line{width:140rpx;height:3rpx;margin:0 12rpx;background:#dfe6ef}.dept-icon-platform{padding:7rpx;border-radius:23rpx;background:#f5f8fd}.departments>view{display:flex;align-items:center;padding:20rpx 0;border-bottom:1rpx solid #edf0f5}.departments>view:last-child{border:0}.departments>view>view:nth-child(2){flex:1;margin-left:18rpx;display:flex;flex-direction:column;gap:7rpx}.departments>view>view:nth-child(2) text:first-child{font-size:26rpx;font-weight:650}.departments>view>view:nth-child(2) text:last-child{color:#8894a8;font-size:20rpx}.selected{padding:22rpx;display:flex;align-items:center}.selected>view:nth-child(2){flex:1;margin-left:15rpx;display:flex;flex-direction:column;color:#8994a7;font-size:20rpx}.selected>view:nth-child(2) text:last-child{color:#142750;font-size:28rpx;font-weight:700}.selected>text{color:#2878ff;font-size:21rpx}.date-scroll{white-space:nowrap;margin-top:20rpx}.date-scroll view{display:inline-block;margin-right:14rpx;padding:17rpx 25rpx;border-radius:20rpx;background:#fff;color:#68758e;font-size:22rpx}.date-scroll .active{background:#2878ff;color:#fff}.doctor{display:flex;align-items:center;padding:27rpx 0;border-bottom:1rpx solid #edf0f5}.avatar{width:78rpx;height:78rpx;border-radius:50%;display:flex;align-items:center;justify-content:center;background:linear-gradient(145deg,#72c8ff,#3478ef);color:#fff}.green-bg{background:linear-gradient(145deg,#62dfc8,#20af96)}.doctor>view:nth-child(2){flex:1;margin-left:17rpx;display:flex;flex-direction:column;gap:7rpx;color:#8490a3;font-size:19rpx}.doctor-name{color:#132751;font-size:24rpx;font-weight:650}.quota{color:#17a47d!important}.doctor>view:last-child{display:flex;flex-direction:column;align-items:center;gap:8rpx}.price{color:#ff7d27;font-size:24rpx}.doctor button{background:#2878ff;color:#fff}.empty{padding:60rpx 0;text-align:center;color:#98a3b5;font-size:22rpx}</style>
